#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int rd(int *s)
{
	int p=0;char ch=getchar();while(ch<'a'||ch>'z')ch=getchar();
	while(ch<='z'&&ch>='a')s[++p]=ch-'a'+1,ch=getchar();return p;
}
typedef long long ll;const int N=1<<20|7,M=998244353;
int a[N],n,hs[N],pw[N],s[27],w[N];bool c[27];
inline void Solve()
{
	n=rd(a);rep(1,n,i)hs[i]=(1ll*pw[i]*a[i]+hs[i-1])%M;
	memset(c,0,sizeof(c));int cur=0;w[n+1]=0;
	drep(n,1,i){(c[a[i]]^=1)?++cur:--cur;w[i]=cur;}
	memset(s,0,sizeof(s));memset(c,0,sizeof(c));cur=0;ll ans=0;
	rep(1,n,i)
	{
		if(i!=1)for(int r=i,tmp=1ll*hs[r]*pw[n-r]%M;r<n&&1ll*(hs[r]-hs[r-i]+M)*pw[n-r]%M==tmp;r+=i)ans+=s[w[r+1]];
		(c[a[i]]^=1)?++cur:--cur;rep(cur,26,i)++s[i];
	}
	printf("%lld\n",ans);
}
int main()
{
	pw[0]=1;rep(1,1<<20|1,i)pw[i]=29ll*pw[i-1]%M;
	int T;scanf("%d",&T);while(T--)Solve();
}
